#include <stdio.h>
#include <fcntl.h>
#include <unistd.h>
#include <string.h>
int main(void) {
    const char *path = "/tmp/kf_dup_test.txt";
    int fd1 = open(path, O_CREAT | O_WRONLY | O_TRUNC, 0644);
    int fd2 = dup(fd1);
    printf("fd1=%d, fd2=%d\n", fd1, fd2);
    write(fd1, "AAA", 3);
    write(fd2, "BBB", 3);
    int fd3 = 10;
    dup2(fd1, fd3);
    write(fd3, "CCC", 3);
    close(fd1);
    close(fd2);
    close(fd3);
    int rfd = open(path, O_RDONLY);
    char buf[32];
    ssize_t n = read(rfd, buf, sizeof(buf) - 1);
    buf[n] = '\0';
    printf("Content: %s\n", buf);
    printf("Length: %zd\n", n);
    close(rfd);
    unlink(path);
    return 0;
}

